file.content:
:root {
  /* Blueprint colors */
  --color-background: #FFFFFF;
  --color-wall-fill: #2D3748;
  --color-wall-stroke: #1A202C;
  --color-grid-minor: #E4E7EC;
  --color-grid-major: #CDD5DF;
  --color-selection: #2B7FFF;
  --color-selection-fill: rgba(43, 127, 255, 0.08);

  /* UI colors */
  --color-text-primary: #1D2939;
  --color-text-secondary: #667085;
  --color-panel-bg: #F9FAFB;
  --color-panel-bg-alt: #FFFFFF;
  --color-border: #D0D5DD;
  --color-accent: #2B7FFF;
  --color-accent-hover: #1D6FE0;
  --color-danger: #DC2626;
  --color-danger-hover: #B91C1C;

  /* Layout */
  --toolbar-height: 48px;
  --sidebar-width: 240px;
  --properties-width: 280px;

  /* Typography */
  --font-ui: 'Inter', system-ui, -apple-system, sans-serif;
  --font-blueprint: 'Courier New', monospace;

  /* Spacing */
  --space-xs: 4px;
  --space-sm: 8px;
  --space-md: 12px;
  --space-lg: 16px;
  --space-xl: 24px;

  /* Borders */
  --radius-sm: 4px;
  --radius-md: 6px;
}

